"""Deterministic risk score generated by the ScoringAgent."""
from pydantic import BaseModel, Field, confloat, conint
from typing import List

from .metadata import Metadata


class RiskComponent(BaseModel):
    """Individual rule‑based risk factor."""
    name: str = Field(..., description="Name of the rule/component.")
    score: conint(ge=0, le=100) = Field(..., description="Score 0‑100.")
    explanation: str = Field(..., description="Why this score was assigned.")


class PartnerScore(BaseModel):
    partner_id: str = Field(..., description="Matches PartnerRawData.partner_id.")
    overall_score: conint(ge=0, le=100) = Field(
        ..., description="Aggregated risk score 0‑100."
    )
    components: List[RiskComponent] = Field(
        default_factory=list,
        description="Breakdown of deterministic rule scores."
    )
    # -------------------------------------------------------
    # Mandatory top‑level confidence for the whole risk profile
    overall_confidence_score: confloat(ge=0.0, le=1.0) = Field(
        ..., description="Aggregate certainty of the entire risk assessment."
    )
    # -------------------------------------------------------
    recommendation: str = Field(
        ..., description="Natural‑language recommendation for the compliance officer."
    )
    recommendation_confidence: confloat(ge=0.0, le=1.0) = Field(
        ..., description="Confidence of the generated narrative recommendation."
    )
    metadata: Metadata = Field(..., description="Execution metadata for ScoringAgent.")
